using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class ShopFloorTraining : TrainingContentBase
{
    public ShopFloorTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Shop Floor Display Overview",
            Slug = "shop-floor-overview",
            Summary = "What the shop floor display is, how kiosk mode works, scan-based authentication, worker cards, and job actions.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/display/shop-floor"]""",
            Tags = """["shop-floor","kiosk","display","clock"]""",
            ContentJson = """{"body":"## Shop Floor Display Overview\n\nThe Shop Floor Display is a full-screen kiosk interface designed for production environments. It runs at `/display/shop-floor` and provides a touch-friendly, always-on dashboard where workers can clock in/out, view their assigned jobs, start and stop timers, mark jobs complete, receive goods, and ship orders — all without navigating the main application.\n\n### Kiosk Mode\n\nThe shop floor display operates in kiosk mode — it is not part of the standard application layout. There is no sidebar, no toolbar, and no header navigation. The entire screen is dedicated to the shop floor interface. It is meant to run on a dedicated monitor or tablet mounted on the production floor.\n\nThe display auto-refreshes every 15 seconds to keep worker status and job data current. A live clock is shown in the header. Theme (light/dark) and font size are persisted to localStorage so the kiosk retains its settings across browser restarts.\n\n### Two Display Variants\n\nThere are two shop floor routes:\n- **`/display/shop-floor`** — the main shop floor display with a worker card grid, unassigned jobs section, upcoming events, and full action overlays (clock, timer, receiving, shipping)\n- **`/display/shop-floor/clock`** — a dedicated clock-in/clock-out kiosk with terminal setup, team filtering, and a simpler scan-first flow using the `BarcodeScanInputComponent` (focused input field)\n\nThe main display uses the global `ScannerService` (passive keyboard-wedge detection on the document), while the clock kiosk uses a focused barcode scan input component.\n\n### Authentication Flow\n\nThe shop floor display uses ephemeral authentication — no persistent login session. Workers authenticate for a single action, then the session is cleared automatically. There are two ways to authenticate:\n\n1. **Scan + PIN:** The worker scans their RFID badge or barcode. The system identifies the scan via the API (`/display/shop-floor/identify-scan`). If it matches an employee, a PIN overlay appears. The worker enters their numeric PIN (minimum 4 digits) and submits. After successful auth, the actions overlay appears.\n\n2. **Card Tap + Password:** The worker taps their name card on the main grid. A password overlay appears (not PIN — full password). After successful auth, the actions overlay appears.\n\nBoth flows use a phase-based state machine: `main → pin → actions → (job-select | receiving | shipping) → main`. Auto-dismiss timeouts prevent stale overlays:\n- PIN phase: 20 seconds before auto-cancel\n- Job selection phase: 15 seconds before auto-cancel\n- Actions phase: 30 seconds of inactivity before auto-logout\n\n### Worker Card Grid\n\nThe main dashboard shows all workers in a responsive grid. Each worker card is a horizontal layout with:\n- A left **status stripe** whose color indicates the worker's clock status (green for working, yellow for break/lunch, gray for clocked out)\n- An **avatar** with the worker's initials and color\n- The worker's **name** and **current status** (short label from ClockEventTypeService)\n- **Elapsed time** since the worker entered their current status (live-updating every second)\n- A list of **assigned jobs** (up to 4 visible, with a '+N more' overflow indicator), each showing the job number, title, stage color dot, and a timer icon if the job has an active timer\n\nWorker cards are interactive — tapping one enters the PIN/password phase. Cards also serve as drop targets for drag-and-drop job assignment from the unassigned jobs section.\n\n### Job Actions\n\nAfter authenticating, the worker sees their assigned jobs with action buttons:\n- **Start Timer** (`play_circle`) — begins tracking time against the selected job\n- **Stop Timer** (`stop_circle`) — stops the running timer\n- **Mark Complete** (`check_circle`) — moves the job to the next stage and logs completion\n\nBelow the jobs, **clock action buttons** are shown dynamically based on the worker's current status (from `ClockEventTypeService`). These include Clock In, Clock Out, Break, Lunch, and any custom clock event types configured in the admin.\n\n### Receiving and Shipping\n\nRole-gated dock actions appear after authentication:\n- **Receive Goods** — available to Admin, Manager, OfficeManager, Engineer, and ProductionWorker roles. Shows open purchase orders with receivable lines, quantity adjustment (+/- buttons), optional bin location selection, and a Receive All confirmation button.\n- **Ship Goods** — available to Admin, Manager, and OfficeManager roles. Shows pending/packed shipments, shipment detail with carrier and tracking info, a Print Packing Slip button, and a Mark Shipped confirmation button.\n\n### IsShopFloor Stage Filter\n\nNot all kanban stages appear on the shop floor. The `IsShopFloor` boolean flag on `TrackType` and `JobStage` entities controls which stages are visible. Only stages marked `IsShopFloor = true` show their jobs on the shop floor display. This filters out non-physical stages like quoting, invoicing, and payment.\n\n### Unassigned Jobs and Drag-and-Drop\n\nUnassigned jobs (jobs with no `assigneeId`) appear in a separate section below the worker grid. Each unassigned job card shows the job number, title, stage name, stage color dot, and priority. Cards are draggable — drag an unassigned job onto a worker card to assign it. After clock-in, if the worker has no assignments, a job picker overlay appears automatically (15-second timeout).\n\n### Upcoming Events\n\nThe shop floor display shows upcoming events (meetings, training sessions, safety events) loaded from the Events API. Each event card shows the type icon, title, start time, location, and a 'Required' badge if applicable.\n\n### Kiosk Settings\n\nThe header includes controls for:\n- **Font size** — increase/decrease buttons with 5 steps (12px, 14px, 16px, 18px, 20px), applied via CSS zoom. Persisted to localStorage as `sf-font-index`.\n- **Theme toggle** — switches between light and dark themes. Persisted to localStorage as `sf-theme`.\n- **Live clock** — displays current time in `HH:MM:SS` format, updating every second.\n- **Kiosk search bar** — a debounced search input (300ms, min 2 chars) that queries `/display/shop-floor/search` for jobs, parts, and other entities.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Shop Floor Display — Guided Tour",
            Slug = "shop-floor-walkthrough",
            Summary = "A guided tour of the shop floor display: header controls, worker cards, scan auth, clock actions, job timers, receiving, and shipping.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/display/shop-floor"]""",
            Tags = """["shop-floor","kiosk","walkthrough"]""",
            ContentJson = """{"appRoute":"/display/shop-floor","startButtonLabel":"Tour Shop Floor","steps":[{"element":".sf-header","popover":{"title":"Shop Floor Header","description":"The header shows the page title, a kiosk search bar, font size controls, a light/dark theme toggle, and a real-time clock. All kiosk settings are saved to localStorage and persist across browser restarts.","side":"bottom"}},{"element":".sf-header__stats","popover":{"title":"Status Summary Bar","description":"Real-time counts of workers currently Working (green), On Break (yellow), Unassigned Jobs, jobs Done Today, and maintenance Alerts (red, shown only when > 0). These refresh automatically every 15 seconds.","side":"bottom"}},{"element":".sf-grid","popover":{"title":"Worker Cards Grid","description":"All workers are shown in a responsive grid. Each card has a colored left stripe (green = working, yellow = break, gray = clocked out), an avatar, the worker's name and status, elapsed time, and up to 4 assigned jobs. Tap a card to authenticate and access clock actions. You can also drag unassigned jobs onto worker cards to assign them.","side":"top"}},{"element":".sf-card","popover":{"title":"Worker Card","description":"A single worker card. The left stripe color matches the worker's clock status. The identity section shows avatar, name, short status label, and live elapsed time. Below that, assigned jobs are listed with stage color dots, job numbers, titles, and timer indicators.","side":"right"}},{"element":".sf-action-bar","popover":{"title":"Action Bar","description":"The bottom bar shows a passive scan prompt and displays scan feedback messages (e.g., 'Job 1055 — Precision Shaft Assembly' or 'Scan not recognized'). Feedback auto-dismisses after 4 seconds.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Shop Floor Field Reference",
            Slug = "shop-floor-field-reference",
            Summary = "Complete reference for the shop floor display: auth flow fields, worker card fields, job action buttons, clock actions, auto-dismiss timeouts, kiosk settings, receiving, shipping, and stage filtering.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/display/shop-floor"]""",
            Tags = """["shop-floor","kiosk","reference"]""",
            ContentJson = """{"title":"Shop Floor Field Reference","groups":[{"heading":"Authentication Flow","items":[{"label":"Scan + PIN","value":"Worker scans RFID badge or barcode → system identifies via API → PIN overlay appears → worker enters numeric PIN (min 4 digits) → submits → actions overlay opens. Uses scanLogin() auth method."},{"label":"Card Tap + Password","value":"Worker taps their name card on the grid → password overlay appears (full password, not PIN) → submits → actions overlay opens. Uses standard login() auth method."},{"label":"PIN field (scan auth)","value":"Numeric input, type=password, min 4 digits, max 8 characters. Placeholder: 'Enter your PIN'. Auto-focused when PIN phase opens."},{"label":"Password field (tap auth)","value":"Text input, type=password, max 128 characters. Placeholder: 'Enter your password'."},{"label":"Submit button","value":"Disabled when authenticating or field empty. Shows 'Verifying...' spinner (sync icon) during auth. Label: 'Submit' with login icon."},{"label":"Cancel button","value":"Returns to main dashboard. Label: 'Cancel' with arrow_back icon."},{"label":"Error messages","value":"'Invalid badge or PIN' for failed scan auth. 'Invalid password' for failed tap auth. 'PIN must be at least 4 digits' for short PINs."}]},{"heading":"Auto-Dismiss Timeouts","items":[{"label":"PIN phase timeout","value":"20 seconds. If the worker does not submit within 20 seconds, the overlay auto-cancels and returns to the main dashboard."},{"label":"Job selection timeout","value":"15 seconds. If the worker does not pick a job or skip within 15 seconds, the overlay auto-cancels and logs out."},{"label":"Actions phase auto-logout","value":"30 seconds of inactivity. Any button press resets the timer. After 30 seconds, the session is cleared and the display returns to the main dashboard."},{"label":"Data refresh interval","value":"15 seconds. Worker status, job data, and upcoming events refresh automatically on the main dashboard."},{"label":"Clock update interval","value":"1 second. The header clock and worker elapsed times update every second."},{"label":"Scan feedback auto-dismiss","value":"4 seconds. Feedback messages in the bottom bar disappear after 4 seconds."},{"label":"Action success feedback","value":"1.5 seconds. After a successful clock action, feedback is shown briefly before auto-logout. 0.8 seconds before transitioning to job picker (if applicable)."}]},{"heading":"Worker Card Fields","items":[{"label":"Status stripe (left border)","value":"Colored vertical stripe on the left edge. Green (sf-card--in) for working status, yellow (sf-card--break) for break/lunch, gray (sf-card--out) for clocked out. Color determined by ClockEventTypeService status mapping."},{"label":"Avatar","value":"AvatarComponent with size 'lg'. Shows worker initials and avatar color."},{"label":"Worker name","value":"Full name displayed in sf-card__name."},{"label":"Status label","value":"Short label from ClockEventTypeService.getShortLabel(). Displayed next to the name."},{"label":"Elapsed time","value":"Live-updating duration since worker entered current status. Format: Xs, Xm XXs, or Xh XXm XXs. Recomputed every second via tick signal."},{"label":"Assigned jobs (max 4 visible)","value":"Each job row shows: stage color dot, job number, job title, and timer icon (if active). Active-timer jobs highlighted. Overdue jobs get overdue styling."},{"label":"Overflow indicator","value":"'+N more' text when worker has more than 4 assignments."},{"label":"Drop target highlight","value":"Visual highlight (sf-card--drop-target) when dragging an unassigned job over the card."},{"label":"Feedback states","value":"Green pulse (sf-card--feedback-success) after successful action. Red pulse (sf-card--feedback-fail) after failed action."}]},{"heading":"Header Stats","items":[{"label":"Working (green)","value":"Count of workers with an active 'working' clock status. Color: var(--success)."},{"label":"On Break (yellow)","value":"Count of workers with break or lunch clock status. Color: var(--warning)."},{"label":"Unassigned","value":"Count of active jobs with no assigneeId."},{"label":"Done Today (accent)","value":"Count of jobs completed today. Color: var(--accent)."},{"label":"Alerts (red)","value":"Count of maintenance alerts. Only shown when > 0. Color: var(--error)."}]},{"heading":"Job Action Buttons (Actions Overlay)","items":[{"label":"Start Timer (play_circle)","value":"Starts tracking time against the selected job. Calls POST /time-tracking/timer/start with jobId. Disabled while any action is processing. Shows spinner during request."},{"label":"Stop Timer (stop_circle)","value":"Stops the currently running timer. Calls POST /time-tracking/timer/stop. Only shown on jobs with an active timer."},{"label":"Mark Complete (check_circle)","value":"Marks the job as complete and moves it to the next stage. Calls POST /display/shop-floor/complete-job. After success, auto-logs out after 1.2 seconds."}]},{"heading":"Clock Action Buttons (Actions Overlay)","items":[{"label":"Dynamic actions","value":"Buttons are generated from ClockEventTypeService.getAvailableActions(worker.status). Each button shows an icon and label from the clock event type definition, with a custom color via --btn-color CSS variable."},{"label":"Clock In","value":"Available when worker is clocked out. Transitions to 'working' status. If worker has no assignments after clock-in, the job picker overlay appears."},{"label":"Clock Out","value":"Available when worker is clocked in. Transitions to 'clocked out' status."},{"label":"Break / Lunch","value":"Available when worker is clocked in. Transitions to break/lunch status."},{"label":"Processing state","value":"All buttons disabled while any action is in progress. Active button shows spinning sync icon."}]},{"heading":"Dock Actions (Role-Gated)","items":[{"label":"Receive Goods (move_to_inbox)","value":"Opens the receiving overlay. Available to Admin, Manager, OfficeManager, Engineer, and ProductionWorker roles. Only shown when the worker is actively clocked in."},{"label":"Ship Goods (local_shipping)","value":"Opens the shipping overlay. Available to Admin, Manager, and OfficeManager roles. Only shown when the worker is actively clocked in."},{"label":"Receiving overlay — PO selection","value":"Lists open purchase orders (status: Submitted, Acknowledged, PartiallyReceived) with receivable lines. Shows PO number, vendor name, and line count."},{"label":"Receiving overlay — line confirmation","value":"Per-line quantity adjustment with +/- buttons. Shows part number, description, remaining quantity. Optional bin location select dropdown."},{"label":"Receiving overlay — Receive All button","value":"Submits all lines with qty > 0. Shows spinner during submission. Auto-logs out after 1.5 seconds on success."},{"label":"Shipping overlay — shipment selection","value":"Lists pending and packed shipments. Shows shipment number, customer name, sales order number, and status chip."},{"label":"Shipping overlay — shipment detail","value":"Shows shipment number, customer, SO number, carrier, tracking number, and line items with descriptions and quantities."},{"label":"Print Packing Slip button","value":"Opens the packing slip PDF in a new tab via GET /shipments/{id}/packing-slip."},{"label":"Mark Shipped button","value":"Confirms shipment. Shows spinner during submission. Auto-logs out after 1.5 seconds on success."}]},{"heading":"Kiosk Settings (Header Controls)","items":[{"label":"Font size decrease (text_decrease)","value":"Reduces font size by one step. Disabled at minimum (12px, index 0). Steps: 12, 14, 16, 18, 20px. Applied via CSS zoom. Persisted to localStorage key 'sf-font-index'."},{"label":"Font size display","value":"Shows current font size in pixels (e.g., '14px')."},{"label":"Font size increase (text_increase)","value":"Increases font size by one step. Disabled at maximum (20px, index 4)."},{"label":"Theme toggle (dark_mode / light_mode)","value":"Switches between light and dark themes. Icon changes based on current theme. Persisted to localStorage key 'sf-theme'. Applied via data-theme attribute on the host element."},{"label":"Live clock","value":"Displays current time in HH:MM:SS AM/PM format. Updates every second."}]},{"heading":"Stage Filtering (IsShopFloor)","items":[{"label":"IsShopFloor flag","value":"Boolean on TrackType and JobStage entities. Controls which stages appear on the shop floor display. Only stages with IsShopFloor = true show their jobs."},{"label":"Purpose","value":"Filters out non-physical stages (quoting, invoicing, payment) that are irrelevant to production floor workers."},{"label":"Configuration","value":"Set via Admin → Track Types. Each stage within a track type can be individually toggled for shop floor visibility."}]},{"heading":"Job Selection Overlay","items":[{"label":"Trigger","value":"Appears automatically after clock-in if the worker has no assigned jobs. Shown after 0.8-second feedback delay."},{"label":"Job list","value":"Shows all unassigned jobs with stage color dot, job number, title, stage name, and priority. Each job is a clickable button."},{"label":"Assign action","value":"Clicking a job assigns it to the worker via POST /display/shop-floor/assign-job. Auto-logs out after 0.8 seconds on success."},{"label":"Skip button","value":"Skips job selection and logs out. Icon: skip_next."},{"label":"Empty state","value":"Shows 'No unassigned jobs available' with work_off icon when no jobs are available."}]},{"heading":"Drag-and-Drop Job Assignment","items":[{"label":"Drag source","value":"Unassigned job cards in the unassigned jobs section. Each card has a drag_indicator handle icon and draggable='true'."},{"label":"Drop target","value":"Worker cards in the main grid. Visual highlight appears when dragging over a card."},{"label":"Assignment","value":"Dropping a job on a worker card calls POST /display/shop-floor/assign-job with jobId and userId. Data refreshes after assignment."},{"label":"Drag data","value":"Job ID transferred via dataTransfer with type 'application/x-job-id'."}]},{"heading":"Scan Identification","items":[{"label":"API endpoint","value":"POST /display/shop-floor/identify-scan with { scanValue }. Returns ScanIdentification with scanType, entityId, entityNumber, entityTitle."},{"label":"Scan types","value":"employee (→ PIN phase), job (→ feedback message), sales-order (→ feedback message), unknown (→ 'Scan not recognized')."},{"label":"Fallback","value":"If identification API fails, the scan value is treated as an employee badge and the PIN overlay opens."},{"label":"Scanner context","value":"ScannerService context set to 'shop-floor'. Only processes scans during the main phase — ignores scans during overlays."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Shop Floor Knowledge Check",
            Slug = "shop-floor-quiz",
            Summary = "Test your knowledge of the shop floor display: kiosk mode, authentication, worker cards, job actions, receiving, shipping, and stage filtering.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/training"]""",
            Tags = """["shop-floor","kiosk","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"sf1","text":"You're setting up a new shop floor kiosk. After opening the display, what is the primary way workers authenticate to perform actions?","options":[{"id":"a","text":"They log in with their email and password through the standard login page"},{"id":"b","text":"They scan their RFID badge or barcode and enter their numeric PIN","isCorrect":true},{"id":"c","text":"An admin logs them in from the admin panel"},{"id":"d","text":"They use a shared kiosk password posted on the wall"}],"explanation":"The shop floor display uses ephemeral scan-based authentication. Workers scan their RFID badge or barcode, then enter their numeric PIN (minimum 4 digits). The session is automatically cleared after the action is complete. Alternatively, workers can tap their name card and enter their full password."},{"id":"sf2","text":"A worker scans their badge at the shop floor kiosk but walks away without entering their PIN. What happens after 20 seconds?","options":[{"id":"a","text":"The system sends a notification to the worker's phone"},{"id":"b","text":"The PIN overlay stays open indefinitely until someone cancels it"},{"id":"c","text":"The PIN overlay auto-cancels and the display returns to the main dashboard","isCorrect":true},{"id":"d","text":"The worker is automatically clocked out"}],"explanation":"The PIN phase has a 20-second auto-dismiss timeout. If the worker doesn't submit within that time, the overlay cancels automatically and the display returns to the main dashboard. This prevents stale overlays from blocking the kiosk for other workers."},{"id":"sf3","text":"On the worker card grid, what does a yellow left stripe on a worker's card indicate?","options":[{"id":"a","text":"The worker is currently working on a job"},{"id":"b","text":"The worker is on break or lunch","isCorrect":true},{"id":"c","text":"The worker is clocked out for the day"},{"id":"d","text":"The worker has an overdue job assignment"}],"explanation":"The left stripe color indicates the worker's clock status: green means working, yellow means on break or lunch, and gray means clocked out. The colors are determined by the ClockEventTypeService status mapping."},{"id":"sf4","text":"A worker clocks in but has no assigned jobs. What happens next on the shop floor display?","options":[{"id":"a","text":"Nothing — the worker sees the standard actions overlay and can log out"},{"id":"b","text":"A job picker overlay appears automatically, showing unassigned jobs the worker can select","isCorrect":true},{"id":"c","text":"The worker is redirected to the kanban board to find a job"},{"id":"d","text":"An alert is sent to the manager to assign a job"}],"explanation":"After clocking in, if the worker has no assigned jobs, a job selection overlay appears automatically (after a brief 0.8-second feedback delay). The worker can pick an unassigned job or skip. The overlay has a 15-second auto-dismiss timeout."},{"id":"sf5","text":"How do you assign an unassigned job to a worker directly from the shop floor main dashboard (without authenticating)?","options":[{"id":"a","text":"Click the unassigned job, then click the worker's name from a dropdown"},{"id":"b","text":"Drag the unassigned job card from the unassigned section and drop it onto the worker's card","isCorrect":true},{"id":"c","text":"Right-click the job and select 'Assign To'"},{"id":"d","text":"You cannot assign jobs from the main dashboard — you must authenticate first"}],"explanation":"Unassigned job cards are draggable. Drag a job from the unassigned jobs section and drop it onto any worker card in the grid. The assignment is made immediately via the API, and the display refreshes. No authentication is required for drag-and-drop assignment."},{"id":"sf6","text":"A Production Worker authenticates on the shop floor kiosk. Which dock actions will they see?","options":[{"id":"a","text":"Both Receive Goods and Ship Goods"},{"id":"b","text":"Receive Goods only","isCorrect":true},{"id":"c","text":"Ship Goods only"},{"id":"d","text":"Neither — dock actions are only for Admin users"}],"explanation":"Receive Goods is available to Admin, Manager, OfficeManager, Engineer, and ProductionWorker roles. Ship Goods is restricted to Admin, Manager, and OfficeManager roles only. Both require the worker to be actively clocked in."},{"id":"sf7","text":"You adjust the font size on the shop floor kiosk to 18px and switch to dark theme. The browser is restarted. What happens to these settings?","options":[{"id":"a","text":"They reset to defaults (12px, light theme)"},{"id":"b","text":"They are preserved — font size and theme are saved to localStorage","isCorrect":true},{"id":"c","text":"Only the theme is preserved, font size resets"},{"id":"d","text":"They are saved to the user's account preferences on the server"}],"explanation":"Both font size (stored as 'sf-font-index' in localStorage) and theme (stored as 'sf-theme' in localStorage) persist across browser restarts. This ensures the kiosk retains its display settings without reconfiguration."},{"id":"sf8","text":"What does the IsShopFloor flag on a job stage control?","options":[{"id":"a","text":"Whether jobs in that stage can be edited from the shop floor"},{"id":"b","text":"Whether jobs in that stage appear on the shop floor display","isCorrect":true},{"id":"c","text":"Whether workers can clock in when assigned to jobs in that stage"},{"id":"d","text":"Whether the stage column is visible on the kanban board"}],"explanation":"The IsShopFloor boolean flag on TrackType and JobStage entities controls visibility on the shop floor display. Only stages with IsShopFloor = true show their jobs. This filters out non-physical stages like quoting, invoicing, and payment that are irrelevant to production floor workers."},{"id":"sf9","text":"During the receiving flow on the shop floor, a worker selects a purchase order. What can they adjust before confirming receipt?","options":[{"id":"a","text":"The vendor name and PO number"},{"id":"b","text":"The quantity to receive for each line item and optionally select a bin location","isCorrect":true},{"id":"c","text":"The unit price and total cost of each line"},{"id":"d","text":"The expected delivery date and carrier information"}],"explanation":"The receiving overlay shows each PO line with its remaining quantity. Workers adjust the receive quantity per line using +/- buttons (capped at the remaining quantity). They can also optionally select a bin location from a dropdown. Clicking 'Receive All' submits all lines with quantity > 0."},{"id":"sf10","text":"A worker starts a timer on a job from the shop floor actions overlay. Where does this timer show up?","options":[{"id":"a","text":"Only in the Time Tracking page — the shop floor display does not show active timers"},{"id":"b","text":"On the worker's card in the main grid, as a timer icon next to the job, and the job row is highlighted in the actions overlay","isCorrect":true},{"id":"c","text":"Only in the header stats bar as a global timer count"},{"id":"d","text":"In a separate timer panel that slides out from the right"}],"explanation":"Active timers are visible in multiple places on the shop floor: the worker's card shows a timer icon (timer) next to the job with an active timer, and the job row in the actions overlay gets an active highlight (sf-actions-card__job--active). The timer is started via POST /time-tracking/timer/start and can be stopped from the same overlay."}]}"""
        });

        Log.Information("Seeded Shop Floor training modules");
    }
}
